class Solution {
public:
    vector<pair<int, int>> findBridges(unordered_map<int, unordered_map<int, int>>& adjacencyList) {
        vector<pair<int, int>> res;
        unordered_map<int, bool> visited;
        unordered_map<int, int> low;
        unordered_map<int, int> disc;
        unordered_map<int, int> parent;
        int time = 0;

        void dfs(int node) {
            visited[node] = true;
            low[node] = disc[node] = time;
            time++;

            for (auto& neighbor : adjacencyList[node]) {
                if (!visited.count(neighbor.first)) {
                    parent[neighbor.first] = node;
                    dfs(neighbor.first);
                    low[node] = min(low[node], low[neighbor.first]);
                    if (low[neighbor.first] > disc[node]) {
                        res.push_back(make_pair(node, neighbor.first));
                    }
                } else if (neighbor.first != parent[node]) {
                    low[node] = min(low[node], disc[neighbor.first]);
                }
            }
        }

        for (auto& node : adjacencyList) {
            if (!visited.count(node.first)) {
                dfs(node.first);
            }
        }

        return res;
    }
};

